#include <random>

void modernRandomExample() {
  std::random_device rd;
  std::mt19937 gen(rd()); // Compliant: high-quality generator
  std::uniform_int_distribution<> dis(0, 99);
  int random_val = dis(gen); // Compliant: proper distribution
}

#include <algorithm>
#include <random>
#include <vector>

void modernShuffle() {
  std::vector<int> vec = {1, 2, 3, 4, 5};
  std::random_device rd;
  std::mt19937 g(rd());
  std::shuffle(vec.begin(), vec.end(), g); // Compliant: modern shuffle
}
